external_knowledge:
- 'weathered the storm of high winds' refers to the condition where the wind speed is greater than 10;
- 'navigated through the rough seas' refers to the finish time of the participants;
- 'from the longest to the shortest journey' means the results are ordered by the average finish time in descending order.

sql:
SELECT name, location
FROM competitions
ORDER BY name ASC;

SELECT name, email
FROM sailors
WHERE date_of_birth < DATE('now', '-30 years');

SELECT DISTINCT sailor_id
FROM achievements
WHERE achievement_name = 'Top 3 Finisher';

external_knowledge:
- 'Navigating through strong winds' refers to performing well in races with high wind speeds;
- 'Top 3 Finisher' is an achievement name indicating a sailor finished in the top 3 in a race;
- 'Wind speed greater than 10' refers to races where the average wind speed was more than 10 knots.

- "shone like stars in the firmament" refers to performing exceptionally well;
- "chosen competition types" refers to the types of competitions (e.g., regatta, race, championship);
- "finishing in the top 3 at least twice" means the sailor has finished in the top 3 positions in the same type of competition at least twice.

sql:
SELECT name, experience_level
FROM sailors
ORDER BY experience_level DESC;

SELECT COUNT(sailor_id) 
FROM membership 
WHERE status = 'active';

SELECT metric_name 
FROM performance_metrics 
WHERE value = (SELECT MAX(value) FROM performance_metrics);

external_knowledge:
- "seasoned sailors" refers to sailors with an experience level of 'expert';
- "achieved greatness multiple times" refers to sailors with more than one achievement;
- "bound to the sport by a lifetime commitment" refers to sailors with a lifetime membership.

sql:
SELECT COUNT(DISTINCT sailor_id)
FROM achievements
WHERE achievement_name = 'Championship Winner';
